# ══════════════════════════════════════════════════════════════════════════════
# AgentCore Gateway — read-only MCP surface over the Admin API
# ══════════════════════════════════════════════════════════════════════════════
#
# NOTE: These resources use the aws_bedrockagentcore_* provider resources.
# The exact attribute names below are based on the provider resource list and
# AgentCore documentation. Verify attribute names against the Terraform AWS
# provider docs once available — some may need adjustment.
# ══════════════════════════════════════════════════════════════════════════════

# ── OAuth2 credential provider (Okta) ────────────────────────────────────────
resource "aws_bedrockagentcore_oauth2_credential_provider" "okta" {
  name = "${local.prefix}-okta"

  oauth2_provider_config {
    custom_oauth2_provider_config {
      discovery_url = "${var.okta_issuer_url}/.well-known/openid-configuration"
    }
  }

  credential_provider_vendor = "CustomOAuth2Provider"

  default_credential_config {
    oauth2_credential_config {
      credential_parameter_type = "OAUTH2_CLIENT_CREDENTIALS"
      oauth2_client_credential_config {
        client_id         = var.okta_client_id
        client_secret_arn = var.okta_client_secret_arn
      }
    }
  }

  tags = {
    Environment = var.env
    Project     = "agent-hal"
    ManagedBy   = "terraform"
  }
}

# ── Workload identity (inbound JWT validation) ──────────────────────────────
resource "aws_bedrockagentcore_workload_identity" "mcp" {
  name = "${local.prefix}-mcp-identity"

  identity_provider_config {
    okta_config {
      issuer_url = var.okta_issuer_url
      audience   = [var.okta_audience]
    }
  }

  tags = {
    Environment = var.env
    Project     = "agent-hal"
    ManagedBy   = "terraform"
  }
}

# ── Gateway ─────────────────────────────────────────────────────────────────
resource "aws_bedrockagentcore_gateway" "mcp" {
  name        = "${local.prefix}-mcp-gateway"
  description = "Read-only MCP gateway for Agent HAL admin API"

  protocol_type = "MCP"

  authorizer_type = "CUSTOM_JWT"
  authorizer_configuration {
    custom_jwt_authorizer_configuration {
      discovery_url          = "${var.okta_issuer_url}/.well-known/openid-configuration"
      allowed_audience       = [var.okta_audience]
      allowed_clients        = [var.okta_client_id]
    }
  }

  tags = {
    Environment = var.env
    Project     = "agent-hal"
    ManagedBy   = "terraform"
  }
}

# ── Gateway target (Admin API + OpenAPI spec) ────────────────────────────────
resource "aws_bedrockagentcore_gateway_target" "admin_api" {
  name       = "${local.prefix}-admin-api"
  gateway_id = aws_bedrockagentcore_gateway.mcp.id

  description = "Agent HAL read-only admin API"

  target_configuration {
    rest_api_target {
      url = var.admin_api_invoke_url

      # OpenAPI spec defining the MCP tool surface
      open_api_schema = file("${path.module}/../../mcp/openapi-readonly.json")
    }
  }

  # Credential provider for outbound calls to the admin API
  credential_provider_configurations {
    credential_provider_id = aws_bedrockagentcore_oauth2_credential_provider.okta.id
    credential_provider_type = "OAUTH2"
  }

  tags = {
    Environment = var.env
    Project     = "agent-hal"
    ManagedBy   = "terraform"
  }
}

